mapper.select:
select a.resource_id, a.resource_name, a.resource_code, a.resource_desc, a.avatar, a.owner_type, a.catalog_id, a.create_time, a.man_user_id, a.create_by, b.agent_type, b.agent_home_url, b.prologue, b.integration_type, b.agent_dev_type, b.create_type, b.terminal, b.open_super_helper, b.tag_name, b.skills, c.user_name as creator_name, COALESCE(d.total, 0) useCount, COALESCE(e.total, 0) focusCount, true as myCreate, true as usesPermissions from ss_resource a left join ss_res_ext_dig_employee b on a.resource_id = b.resource_id left join po_users c on a.create_by = c.user_id
left join ( select mem_obj_id, count(1) as total from byai_session_member where mem_obj_type = 'AGENT' group by mem_obj_id ) d on a.resource_id = d.mem_obj_id
left join ( select grant_obj_id, sum(1) as total from au_privilege_grant where grant_obj_type = 'DIG_EMPLOYEE' and grant_type in ('AVAILABLE_USE','FORCE_USE') and status_cd = 'A' and grant_to_type = 'RED' and grant_to_obj_type = 'USER' group by grant_obj_id ) e on a.resource_id = e.grant_obj_id
and a.resource_biz_type = 'DIG_EMPLOYEE' and a.resource_status = 2
and a.create_by = #{userId}
and a.catalog_id in
#{catalogIdItem}
and a.catalog_id = #{catalogId}
and a.resource_name like concat('%', #{keyword}, '%')
order by a.create_time desc

select a.grant_obj_id, b.user_id as manPrivId, b.user_name as manPrivName from au_privilege_grant a join po_users b on a.grant_to_obj_id = b.user_id where grant_type = 'ALLOW_MANAGE' and a.grant_obj_type = 'DIG_EMPLOYEE' and a.grant_to_obj_type = 'USER' and a.status_cd = 'A'
and a.grant_obj_id in
#{item}

select a.org_id, a.org_name, a.parent_org_id, a.path_code from po_organization a inner join po_users_organization b on a.org_id = b.org_id
and b.user_id = #{userId}
order by a.org_level asc, a.org_id asc

select a.resource_id, a.resource_source_pk_id, a.resource_code, a.resource_name, a.resource_desc, a.resource_biz_type, a.create_by, a.create_time, a.man_org_id, a.man_user_id, a.update_time from ss_resource a left join ( select grant_obj_id, sum(case when grant_to_type = 'RED' and status_cd = 'A' then 1 else 0 end) as red_count, sum(case when grant_to_type = 'BLACK' and status_cd = 'A' then 1 else 0 end) as black_count from au_privilege_grant where grant_type in ('AVAILABLE_USE', 'FORCE_USE') and grant_obj_type in ('KG_DOC', 'KG_QA', 'KG_TERM') and status_cd = 'A'
or (grant_to_obj_type = 'ORG' and grant_to_obj_id in
#{orgId}
)
or (grant_to_obj_type = 'USER' and grant_to_obj_id = #{userId})
or (grant_to_obj_type = 'POST' and grant_to_obj_id in
#{positionId}
)
or (grant_to_obj_type = 'STATION' and grant_to_obj_id = #{userStationId})
group by grant_obj_id ) k on a.resource_id = k.grant_obj_id left join ss_res_ext_doc b on a.resource_id=b.resource_id
and a.resource_status = 2
and (k.black_count = 0 or k.black_count is null)
and a.create_by = #{userId}
and (k.red_count > 0 and a.create_by != #{userId})
and (k.red_count > 0 or a.create_by = #{userId})
and a.resource_name like concat('%', #{keyword}, '%')
and a.resource_biz_type in
#{bizType}
and a.resource_biz_type in ('KG_DOC', 'KG_QA', 'KG_TERM')
order by a.create_time desc, a.update_time desc
